import{_ as e,c as a,o,d as n}from"./app.82f05033.js";const r="/vue-docker/assets/devops.92c27c36.png",t="/vue-docker/assets/intro.d0083b44.png",b=JSON.parse('{"title":"Introducci\xF3n","description":"","frontmatter":{},"headers":[{"level":2,"title":"Fuente de origen","slug":"fuente-de-origen","link":"#fuente-de-origen","children":[]},{"level":2,"title":"Efectos de DevOps","slug":"efectos-de-devops","link":"#efectos-de-devops","children":[]},{"level":2,"title":"Efectos de entrega continua","slug":"efectos-de-entrega-continua","link":"#efectos-de-entrega-continua","children":[]}],"relativePath":"guide/intro.md"}'),i={name:"guide/intro.md"},c=n('<h1 id="introduccion" tabindex="-1">Introducci\xF3n <a class="header-anchor" href="#introduccion" aria-hidden="true">#</a></h1><h2 id="fuente-de-origen" tabindex="-1">Fuente de origen <a class="header-anchor" href="#fuente-de-origen" aria-hidden="true">#</a></h2><p>Esta gu\xEDa es una adaptaci\xF3n de un excelente art\xEDculo ejemplificado en <a href="https://en.reactjs.org/" target="_blank" rel="noreferrer">React</a> y publicado bajo el t\xEDtulo <a href="https://levelup.gitconnected.com/docker-for-frontend-developers-4eeaedf10dc7" target="_blank" rel="noreferrer">Docker for frontend developers</a>. Por lo tanto, se puede adaptar a cualquier proyecto frontend; traducido y adaptado por <a href="https://github.com/ejimenez123" target="_blank" rel="noreferrer">Ernesto Canquiz</a>.</p><blockquote><p>Teniendo presente lo antes mencionado, entonces, vamos a sumergirnos...</p></blockquote><h2 id="efectos-de-devops" tabindex="-1">Efectos de DevOps <a class="header-anchor" href="#efectos-de-devops" aria-hidden="true">#</a></h2><p><img src="'+r+'" alt="conclusion"></p><blockquote><p>Concepto extraido de <a href="https://es.vuejs.org/v2/cookbook/dockerize-vuejs-app.html#Efectos-de-DevOps" target="_blank" rel="noreferrer">este</a> enlace.</p></blockquote><p>La adopci\xF3n de la cultura <a href="https://www.netapp.com/es/devops-solutions/what-is-devops/" target="_blank" rel="noreferrer">DevOps</a>, herramientas y practicas \xE1giles de ingenier\xEDa tienen, por sobre todas las cosas, el lindo efecto de incrementar la colaboraci\xF3n entre los roles de desarrollo y operaciones.</p><p>Uno de los principales problemas del pasado (pero tambi\xE9n hoy en d\xEDa en algunas realidades) es que el equipo de desarrollo no estaba interesado en la operaci\xF3n y el mantenimiento de un sistema una vez que se entreg\xF3 al equipo de operaciones, mientras que este \xFAltimo no estaba realmente consciente de los objetivos de negocio, y por lo tanto, reacios a satisfacer las necesidades operativas del sistema (tambi\xE9n denominados \u201Ccaprichos de los desarrolladores\u201D).</p><blockquote><p>Por lo tanto, entregar nuestra aplicaci\xF3n Vue.js como una imagen de Docker ayuda a reducir, si no eliminar por completo, la diferencia entre ejecutar el servicio en la computadora port\xE1til de un desarrollador, el entorno de producci\xF3n o cualquier otro entorno en el que podamos pensar.</p></blockquote><h2 id="efectos-de-entrega-continua" tabindex="-1">Efectos de entrega continua <a class="header-anchor" href="#efectos-de-entrega-continua" aria-hidden="true">#</a></h2><blockquote><p>Concepto extraido de <a href="https://es.vuejs.org/v2/cookbook/dockerize-vuejs-app.html#Efectos-de-entrega-continua" target="_blank" rel="noreferrer">este</a> enlace.</p></blockquote><p>Al aprovechar la disciplina de entrega continua se construye software de tal forma que se puede potencialmente liberar en producci\xF3n en cualquier momento. Dicha pr\xE1ctica de ingenier\xEDa se habilita por medio de lo que normalmente se llama pipeline de entrega continua. El prop\xF3sito del pipeline de entrega continua es dividir nuestra construcci\xF3n en etapas (por ejemplo, compilaci\xF3n, pruebas unitarias, pruebas de integraci\xF3n, pruebas de rendimiento, etc.) y dejar que cada etapa verifique nuestro artefacto de compilaci\xF3n cada vez que cambie nuestro software. En \xFAltima instancia, cada etapa aumenta nuestra confianza de que tan lista para producci\xF3n se encuentra nuestra compilaci\xF3n y, por lo tanto, reduce el riesgo de romper cosas en producci\xF3n (o cualquier otro entorno).</p><blockquote><p>Por lo tanto, crear una imagen de Docker para nuestra aplicaci\xF3n Vue.js es una buena opci\xF3n aqu\xED porque representar\xEDa nuestro artefacto de construcci\xF3n final, el mismo artefacto que se verificar\xE1 contra nuestra entrega continua y que potencialmente podr\xEDa liberarse a producci\xF3n con confianza.</p></blockquote><p><img src="'+t+'" alt="conclusion"></p>',15),s=[c];function d(l,p,u,f,m,h){return o(),a("div",null,s)}const v=e(i,[["render",d]]);export{b as __pageData,v as default};
